.darma-loader-uiverse-bicycle-blueprint__body,
.darma-loader-uiverse-bicycle-blueprint__front,
.darma-loader-uiverse-bicycle-blueprint__handlebars,
.darma-loader-uiverse-bicycle-blueprint__pedals,
.darma-loader-uiverse-bicycle-blueprint__pedals-spin,
.darma-loader-uiverse-bicycle-blueprint__seat,
