.darma-loader-uiverse-liquid-glass-orb { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-liquid-glass-orb__liquid-loader {
  /* Component-scope variables only */
  --ll-bg-1: #ffffff;
  --ll-bg-2: #f7f2ff;
  --ll-bg-3: #eee6ff;

--ll-edge: rgba(111, 83, 214, 0.18);
--ll-edge-bright: rgba(255, 255, 255, 0.86);

--ll-shadow: rgba(54, 36, 116, 0.18);
--ll-shadow-strong: rgba(54, 36, 116, 0.3);
--ll-contact: rgba(49, 28, 104, 0.2);

--ll-text: #2d2059;

--ll-orb-1: #d8cbff;
--ll-orb-2: #a98cff;
--ll-orb-3: #7650f2;
--ll-orb-4: #3f18ad;
--ll-orb-deep: #251064;

--ll-glow: rgba(144, 112, 255, 0.42);
--ll-bubble: rgba(255, 255, 255, 0.94);
--ll-bubble-soft: rgba(255, 255, 255, 0.42);
--ll-focus: rgba(133, 107, 255, 0.34);

display: inline-block;
perspective: 72em;
transform-style: preserve-3d;
}

/* Main pill shell */
.darma-loader-uiverse-liquid-glass-orb__liquid-loader__shell {
position: relative;
display: inline-flex;
align-items: center;
justify-content: center;
gap: 0.95em;

min-width: 12.2em;
min-height: 4.7em;
padding: 0.9em 1.2em;

border-radius: 999em;
border: 0.08em solid var(--ll-edge);

/*
3D shell stack: - top light - soft center body - darker lower bevel
*/
background: linear-gradient(
180deg,
rgba(255, 255, 255, 0.95) 0%,
rgba(255, 255, 255, 0.5) 18%,
transparent 42%
),
radial-gradient(
ellipse at 22% 8%,
rgba(255, 255, 255, 0.92) 0%,
rgba(255, 255, 255, 0.38) 24%,
transparent 48%
),
linear-gradient(
165deg,
var(--ll-bg-1) 0%,
var(--ll-bg-2) 54%,
var(--ll-bg-3) 100%
);

/*
Deep 3D shadowing: - outside drop shadow - contact shadow - upper bevel - lower inset shadow
*/
box-shadow:
0 1.45em 2.8em var(--ll-shadow),
0 0.65em 0.85em -0.65em var(--ll-contact),
inset 0 0.16em 0.22em var(--ll-edge-bright),
inset 0 -0.58em 1.05em rgba(91, 60, 188, 0.16),
inset 0 -0.12em 0.16em rgba(54, 28, 132, 0.12),
inset 0 0 0 0.055em rgba(255, 255, 255, 0.5);

transform-style: preserve-3d;
transform: rotateX(0deg) rotateY(0deg) translateZ(0);
translate: 0 0;

overflow: hidden;
cursor: default;
outline: none;
user-select: none;

transition:
transform 260ms cubic-bezier(0.22, 1, 0.36, 1),
box-shadow 260ms cubic-bezier(0.22, 1, 0.36, 1),
border-color 260ms ease;

animation: darma-loader-uiverse-liquid-glass-orb-ll-shell-float 4s ease-in-out infinite;
}

/* Moving premium glass sweep across shell */
.darma-loader-uiverse-liquid-glass-orb__liquid-loader__shell::before {
content: "";
position: absolute;
inset: 0.18em;
border-radius: inherit;

background: linear-gradient(
115deg,
transparent 0%,
transparent 18%,
rgba(255, 255, 255, 0.78) 28%,
rgba(255, 255, 255, 0.22) 39%,
transparent 58%
);

transform: translateX(-135%) skewX(-8deg);
pointer-events: none;
z-index: 3;

animation: darma-loader-uiverse-liquid-glass-orb-ll-shell-sheen 4.2s cubic-bezier(0.22, 1, 0.36, 1) infinite;
}

/* Lower-right internal glow / 3D weight */
.darma-loader-uiverse-liquid-glass-orb__liquid-loader__shell::after {
content: "";
position: absolute;
width: 5em;
height: 5em;
right: -1.75em;
bottom: -1.95em;

border-radius: 50%;

background: radial-gradient(
circle,
rgba(144, 112, 255, 0.42) 0%,
rgba(144, 112, 255, 0.18) 34%,
transparent 72%
);

filter: blur(0.28em);
pointer-events: none;
z-index: 0;
}

/* Accessible focus ring */
.darma-loader-uiverse-liquid-glass-orb__liquid-loader:focus-visible .darma-loader-uiverse-liquid-glass-orb__liquid-loader__shell,
.darma-loader-uiverse-liquid-glass-orb__liquid-loader__shell:focus-visible {
box-shadow:
0 1.45em 2.8em var(--ll-shadow),
0 0 0 0.24em var(--ll-focus),
inset 0 0.16em 0.22em var(--ll-edge-bright),
inset 0 -0.58em 1.05em rgba(91, 60, 188, 0.16),
inset 0 0 0 0.055em rgba(255, 255, 255, 0.5);
}

/* Hover adds physical tilt */
.darma-loader-uiverse-liquid-glass-orb__liquid-loader:hover .darma-loader-uiverse-liquid-glass-orb__liquid-loader__shell {
transform: rotateX(6deg) rotateY(-4deg) translateZ(0.3em);
border-color: rgba(111, 83, 214, 0.24);

box-shadow:
0 1.75em 3.2em var(--ll-shadow-strong),
0 0.8em 1em -0.65em var(--ll-contact),
inset 0 0.18em 0.26em rgba(255, 255, 255, 0.92),
inset 0 -0.68em 1.2em rgba(91, 60, 188, 0.19),
inset 0 -0.12em 0.16em rgba(54, 28, 132, 0.14),
inset 0 0 0 0.055em rgba(255, 255, 255, 0.58);
}

/* Pressed state feels like soft silicone */
.darma-loader-uiverse-liquid-glass-orb__liquid-loader:active .darma-loader-uiverse-liquid-glass-orb__liquid-loader__shell {
transform: rotateX(2deg) rotateY(-1deg) translateZ(0) scale(0.985);
}

/* Main liquid glass orb */
.darma-loader-uiverse-liquid-glass-orb__liquid-loader__orb {
position: relative;
width: 2.55em;
height: 2.55em;
flex: 0 0 auto;

border-radius: 50%;
overflow: hidden;
isolation: isolate;

/*
No hard static shine circles here.
This uses broad lighting gradients instead.
*/
background: linear-gradient(
145deg,
rgba(255, 255, 255, 0.52) 0%,
rgba(255, 255, 255, 0.16) 24%,
transparent 42%
),
radial-gradient(
ellipse at 42% 28%,
var(--ll-orb-1) 0%,
var(--ll-orb-2) 30%,
var(--ll-orb-3) 64%,
var(--ll-orb-4) 86%,
var(--ll-orb-deep) 100%
);

/*
Orb depth: - floor shadow - violet glow - glass rim - heavy lower internal shade
*/
box-shadow:
0 0.72em 1.2em rgba(72, 38, 184, 0.34),
0 0 1.25em rgba(137, 104, 255, 0.28),
inset 0 0.16em 0.22em rgba(255, 255, 255, 0.58),
