inset 0.16em 0.18em 0.28em rgba(255, 255, 255, 0.2),
inset 0 0 0 0.075em rgba(255, 255, 255, 0.18);

transform-style: preserve-3d;
transform: translateZ(0.6em);

animation:
darma-loader-uiverse-liquid-glass-orb-ll-orb-float 2.8s cubic-bezier(0.37, 0, 0.22, 1) infinite,
darma-loader-uiverse-liquid-glass-orb-ll-orb-wobble 4.8s ease-in-out infinite;
}

/* Internal liquid lens, not a static shine dot */
.darma-loader-uiverse-liquid-glass-orb__liquid-loader__orb::before {
content: "";
position: absolute;
inset: 0.12em;
border-radius: inherit;

background: linear-gradient(
155deg,
