/* Soft liquid surface curve */
.darma-loader-uiverse-liquid-glass-orb__liquid-loader__orb::after {
content: "";
position: absolute;
left: -18%;
top: 13%;
width: 136%;
height: 64%;

border-radius: 48% 52% 54% 46% / 42% 44% 56% 58%;

